### Step 2: Define the `GameBoard` Class

```python
import numpy as np

class GameBoard:
    EMPTY = ' '
    WHITE = 'W'
    BLACK = 'B'
    KING_WHITE = 'Kw'
    KING_BLACK = 'Kb'

    def __init__(self):
        self.board = np.array([
            [self.BLACK if (i + j) % 2 else self.EMPTY for i in range(8)] for j in range(8)
        ])
        self.white_pieces = []
        self.black_pieces = []

        # Place initial pieces
        for row in range(3):
            for col in range(8):
                if (row + col) % 2 == 1:
                    self.board[row, col] = self.BLACK
                    self.black_pieces.append((row, col))

        for row in range(5, 8):
            for col in range(8):
                if (row + col) % 2 == 1:
                    self.board[row, col] = self.WHITE
                    self.white_pieces.append((row, col))

    def move_piece(self, from_pos, to_pos):
        row_from, col_from = from_pos
        row_to, col_to = to_pos

        piece = self.board[row_from, col_from]
        if piece == self.EMPTY:
            return False

        # Move the piece and capture if applicable
        if (abs(row_to - row_from) == 2 and abs(col_to - col_from) == 2):
            mid_row = (row_from + row_to) // 2
            mid_col = (col_from + col_to) // 2
            self.board[mid_row, mid_col] = self.EMPTY

        self.board[row_from, col_from] = self.EMPTY
        self.board[row_to, col_to] = piece

        # Update piece list
        if self.board[row_to, col_to].isupper():
            self.white_pieces.append((row_to, col_to))
        else:
            self.black_pieces.append((row_to, col_to))

        return True

    def is_valid_move(self, from_pos, to_pos):
        row_from, col_from = from_pos
        row_to, col_to = to_pos

        piece = self.board[row_from, col_from]
        if piece == self.EMPTY:
            return False

        if abs(row_to - row_from) != 1 or abs(col_to - col_from) != 1:
            return False

        if piece.islower() and row_to > row_from:  # White can only move up
            return False

        if piece.isupper() and row_to < row_from:  # Black can only move down
            return False

        target = self.board[row_to, col_to]
        if target != self.EMPTY:
            return False

        return True

    def display(self):
        print("   a b c d e f g h")
        for i in range(8):
            row = ' '.join([self.board[i, j] if self.board[i, j] else '.' for j in range(8)])
            print(f"{i + 1} {row}")
```

### Step 3: Define the `Player` Class

```python
class Player:
    def __init__(self, color):
        self.color = color

    def make_move(self, board):
        while True:
            move = input(f"Enter your move ({self.color}): ")
            if self.validate_move(move, board):
                return move
            print("Invalid move. Please try again.")

    def validate_move(self, move, board):
        from_pos, to_pos = move.split('-')
        row_from, col_from = ord(from_pos[1]) - 97, int(from_pos[0]) - 1
        row_to, col_to = ord(to_pos[1]) - 97, int(to_pos[0]) - 1

        return board.is_valid_move((row_from, col_from), (row_to, col_to))
```

### Step 4: Define the `GameEngine` Class

```python
class GameEngine:
    def __init__(self):
        self.board = GameBoard()
        self.current_player = Player(GameBoard.WHITE)

    def play(self):
        while True:
            self.board.display()
            move = self.current_player.make_move(self.board)
            row_from, col_from = ord(move[0][1]) - 97, int(move[0][0]) - 1
            row_to, col_to = ord(move[2][1]) - 97, int(move[2][0]) - 1

            if not self.board.move_piece((row_from, col_from), (row_to, col_to)):
                print("Invalid move. Please try again.")
                continue

            # Switch players
            self.current_player = Player(GameBoard.BLACK) if self.current_player.color == GameBoard.WHITE else Player(GameBoard.WHITE)
```

### Step 5: Main Execution

```python
if __name__ == "__main__":
    engine = GameEngine()
    engine.play()
```

